from clayers import ClayersError, SpecError, KnowledgeModel

try:
    km = KnowledgeModel("/nonexistent/path")
except SpecError as e:
    print(f"Spec problem: {e}")  # catches only spec errors
except ClayersError as e:
    print(f"Any clayers error: {e}")  # catches all subtypes
